import logging
import os
import json
import azure.functions as func
from azure.identity import ManagedIdentityCredential
from azure.storage.blob import BlobServiceClient
from azure.cosmos import CosmosClient, PartitionKey
from azure.eventgrid import EventGridPublisherClient, EventGridEvent

def main(myblob: func.InputStream):
    logging.info(f"Processing blob: {myblob.name}")

    # Managed Identity Credential
    credential = ManagedIdentityCredential()

    # Blob Storage Client
    blob_service_client = BlobServiceClient(account_url=os.getenv('BLOB_ACCOUNT_URL'), credential=credential)
    container_client = blob_service_client.get_container_client(os.getenv('BLOB_CONTAINER_NAME'))
    blob_client = container_client.get_blob_client(myblob.name)

    # Read blob content
    blob_content = myblob.read()
    logging.info(f"Blob content: {blob_content}")

    # Process the blob content (dummy processing)
    processed_data = {"processed": True, "content": blob_content.decode('utf-8')}

    # Cosmos DB Client
    cosmos_client = CosmosClient(url=os.getenv('COSMOS_DB_URL'), credential=credential)
    database_name = os.getenv('COSMOS_DB_NAME')
    container_name = os.getenv('COSMOS_DB_CONTAINER_NAME')
    database = cosmos_client.get_database_client(database_name)
    container = database.get_container_client(container_name)

    # Write to Cosmos DB
    container.upsert_item({
        'id': myblob.name,
        'data': processed_data
    })

    # Event Grid Client
    event_grid_client = EventGridPublisherClient(endpoint=os.getenv('EVENT_GRID_ENDPOINT'), credential=credential)

    # Send notification via Event Grid
    event = EventGridEvent(
        subject="BlobProcessed",
        event_type="BlobProcessing.Complete",
        data={"blobName": myblob.name, "status": "Processed"},
        data_version="1.0"
    )
    event_grid_client.send([event])

    logging.info(f"Blob {myblob.name} processed and notification sent.")